mapper.insert:
INSERT INTO ANSWER_RECORD (
    QUESTION_ID, USER_ID, SESSION_ID, SELECTED_ANSWER, CORRECT_ANSWER, IS_CORRECT, START_TIME, END_TIME, CREATED_TIME, UPDATED_TIME
) VALUES (
    #{questionId}, #{userId}, #{sessionId}, #{selectedAnswer}, #{correctAnswer}, #{isCorrect}, #{startTime}, #{endTime}, #{createdTime}, #{updatedTime}
)

mapper.sql:
USER_ID = #{userId}

    AND QUESTION_ID = #{questionId}


    AND IS_CORRECT = #{isCorrect}


    AND END_TIME >= #{startTime}


    AND END_TIME <= #{endTime}

mapper.select:
SELECT CAST(COALESCE(AVG(TIMESTAMPDIFF(MICROSECOND, START_TIME, END_TIME) / 1000), 0) AS UNSIGNED)
FROM ANSWER_RECORD
WHERE USER_ID = #{userId}
